// ── Parse Drive Results ──────────────────────────────────────────────
// Returns one item per supported file so the next HTTP Request loops them.

const data = $input.first().json;
const question = $('Normalize Inputs').first().json.question;
const files = data.files || [];

// File types Google Drive can export as plain text
const exportable = [
  'application/vnd.google-apps.document',
  'application/vnd.google-apps.spreadsheet',
  'application/vnd.google-apps.presentation',
  'text/plain',
  'text/markdown',
  'text/csv'
];
// PDFs are downloaded (alt=media) rather than exported
const downloadable = ['application/pdf'];

const allSupported = [...exportable, ...downloadable];
const filtered = files.filter(f => allSupported.includes(f.mimeType));

if (filtered.length === 0) {
  // Return a sentinel that the next node will propagate as an empty context
  return [{
    json: {
      file_id: '__NO_DOCS__',
      file_name: 'none',
      mime_type: 'none',
      modified: '',
      question,
      no_docs: true
    }
  }];
}

// One item per file — n8n will process each through the next node
return filtered.map(f => ({
  json: {
    file_id: f.id,
    file_name: f.name,
    mime_type: f.mimeType,
    modified: f.modifiedTime,
    question,
    no_docs: false,
    // Flag: Google Workspace files need /export, others need alt=media
    export_mode: exportable.includes(f.mimeType) ? 'export' : 'download'
  }
}));

// ── Extract & Truncate Text ──────────────────────────────────────────
// Re-attaches file metadata (lost after HTTP Request) using $('Parse Drive Results').item

const rawText = $json.data || $json.body || '';
const fileInfo = $('Parse Drive Results').item.json;

// Skip sentinel / no-doc items
if (fileInfo.no_docs || fileInfo.file_id === '__NO_DOCS__') {
  return [{ json: { file_name: 'none', file_id: 'none', text_snippet: '', char_count: 0, question: fileInfo.question, no_docs: true } }];
}

// Clean control chars and normalize whitespace
const cleaned = String(rawText)
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ')
  .replace(/[ \t]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Limit each document to 3,500 chars to keep the combined context within GPT token budget
const MAX_CHARS = 3500;
const truncated = cleaned.length > MAX_CHARS
  ? cleaned.slice(0, MAX_CHARS) + '... [content truncated]'
  : cleaned;

return [{
  json: {
    file_name: fileInfo.file_name,
    file_id: fileInfo.file_id,
    text_snippet: truncated,
    char_count: truncated.length,
    question: fileInfo.question,
    no_docs: false
  }
}];

// ── Build RAG Context ────────────────────────────────────────────────
// Combines all document excerpts into a structured prompt for GPT-4o-mini.

const allDocs = $input.first().json.data || [];
const question = allDocs[0]?.question || 'Unknown question';

// Filter out no-doc sentinels and empty snippets
const validDocs = allDocs.filter(d => !d.no_docs && d.text_snippet && d.text_snippet.length > 10);

if (validDocs.length === 0) {
  // No readable content — still send to OpenAI, it will reply accordingly
  return [{
    json: {
      question,
      system_prompt: 'You are a document assistant. No documents were found for the user query. Tell the user politely that no relevant documents were found in their Google Drive.',
      user_prompt: `Question: ${question}`,
      source_files: [],
      doc_count: 0,
      context_chars: 0
    }
  }];
}

// Format context blocks with clear document separators
const contextBlocks = validDocs.map((doc, i) =>
  `=== Document ${i + 1}: "${doc.file_name}" ===\n${doc.text_snippet}\n`
).join('\n');

const sourceList = validDocs.map(d => d.file_name);

const systemPrompt = `You are a precise, helpful document Q&A assistant. Answer the user's question using ONLY the content from the provided documents.

Your Rules:
1. Base your answer exclusively on the document content shown — do not invent facts.
2. Cite which document(s) contain the supporting information.
3. If the answer is not present in any document, respond: "The documents provided do not contain information about this topic."
4. Be concise, clear, and actionable.
5. ALWAYS respond with valid JSON in this exact format:
{
  "answer": "your full answer here",
  "sources": ["Document Name 1", "Document Name 2"],
  "confidence": "high | medium | low",
  "summary": "one sentence summary of the answer",
  "follow_up_questions": ["Suggested Q 1", "Suggested Q 2"]
}`;

const userPrompt = `Documents:\n${contextBlocks}\n\nQuestion: ${question}`;

return [{
  json: {
    question,
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    source_files: sourceList,
    doc_count: validDocs.length,
    context_chars: contextBlocks.length
  }
}];

