// ── Parse AI Answer ──────────────────────────────────────────────────
// Safely parses the GPT JSON response and assembles the final result object.

const aiResponse = $json;
const contextNode = $('Build RAG Context').first().json;
const rawContent = aiResponse.choices?.[0]?.message?.content || '{}';

let parsed = {};
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  // Fallback: try to extract JSON block from freeform text
  const match = rawContent.match(/\{[\s\S]*\}/);
  try {
    parsed = match ? JSON.parse(match[0]) : {};
  } catch {
    parsed = {};
  }
}

// Normalize all fields with safe defaults
const result = {
  question: contextNode.question,
  answer: parsed.answer || rawContent || 'No answer was generated. Please try rephrasing your question.',
  sources: Array.isArray(parsed.sources) ? parsed.sources : contextNode.source_files,
  confidence: parsed.confidence || 'medium',
  summary: parsed.summary || '',
  follow_up_questions: Array.isArray(parsed.follow_up_questions) ? parsed.follow_up_questions : [],
  doc_count: contextNode.doc_count,
  context_chars: contextNode.context_chars,
  model: 'gpt-4o-mini',
  tokens_used: aiResponse.usage?.total_tokens || 0,
  prompt_tokens: aiResponse.usage?.prompt_tokens || 0,
  completion_tokens: aiResponse.usage?.completion_tokens || 0,
  estimated_cost_usd: ((aiResponse.usage?.prompt_tokens || 0) * 0.00000015 + (aiResponse.usage?.completion_tokens || 0) * 0.0000006).toFixed(6),
  timestamp: new Date().toISOString()
};

return [{ json: result }];

